      ch_id, 'aiq-mat-029', 'Warm-Up: Patterns in Mathematics', 'warm_up', 'Warm-Up',
      29, 15, ARRAY['pattern_recognition','data_reasoning']::text[], 'published', '{"quest_code": "AIQ-MAT-029", "theme": "Patterns in Mathematics", "difficulty": "Developing", "stars": 2, "emoji": "📘", "accent": "teal", "source": "AIQ_Grade6_Math_Teacher_Guide"}'::jsonb,
      'AIQ-MAT-029', TRUE, 'developing', 'enriched', '{"socratic_branch": "Ask students to say both the arithmetic rule and the real-world limitation. If they only state the formula, push: “If over 11 scores just 2 runs, has the rule failed, or has the situation changed? How would an AI know the difference?”", "answer": "Rule: runs = 4 x over number, so over 10 = 40 runs. An AI batting coach uses this repeating pattern to predict future scores -- but one unusual over (like scoring only 2) doesn''t necessarily break the rule; it may just be natural variation, which a good AI should tell apart from a real change in form.", "source": "AIQ_Grade6_Math_Teacher_Guide", "excel_activity_label": "Warm-Up"}'::jsonb
    ) RETURNING id INTO act_id;

    INSERT INTO questions (activity_id, role, sort_order, stem, hint, answer_spec, context)
    VALUES (
      act_id, 'stem', 0, 'Sequence Detective: A cricket team scores 4, 8, 12, 16, ... runs in successive overs. Write the rule. Predict the 10th over score. How could an AI batting coach use this pattern? Now push further: if over 11 suddenly scores only 2 runs, does that break your rule, or just mean the rule has limits — how would you tell the difference?', 'Look at how the runs increase from one over to the next before predicting the 10th.',
      '{"answer_type": "short_text", "body": {"value": "Rule: runs = 4 x over number, so over 10 = 40 runs. An AI batting coach uses this repeating pattern to predict future scores -- but one unusual over (like scoring only 2) doesn''t necessarily break the rule; it may just be natural variation, which a good AI should tell apart from a real change in form."}}'::jsonb,
      '{"grade": 6, "chapter_dependent": true, "external_id": "AIQ-MAT-029"}'::jsonb
    ) RETURNING id INTO stem_id;

