      'AIQ-MAT-030', TRUE, 'proficient', 'enriched', '{"socratic_branch": "This is intentionally tricky. Reward students who identify missing information. If they don''t spot it, push: “Could two different triangles both have sides 3 m, 4 m, 5 m but different angles — or is this triangle''s shape actually fixed? How would you check?”", "answer": "A right-angled 3-4-5 triangle has one guaranteed 90-degree angle; the other two angles need measuring or calculating, not guessing -- exactly the precision a navigation app needs before giving turn-by-turn directions.", "source": "AIQ_Grade6_Math_Teacher_Guide", "excel_activity_label": "Warm-Up"}'::jsonb
    ) RETURNING id INTO act_id;

