    );
    INSERT INTO questions (activity_id, role, sort_order, label, stem, hint, teacher_notes)
    VALUES (
      act_id, 'coach_step', 2, 'Think Together', 'This is intentionally tricky. Reward students who identify missing information. If they don''t spot it, push: “Could two different triangles both have sides 3 m, 4 m, 5 m but different angles — or is this triangle''s shape actually fixed? How would you check?”', 'Only one angle is fixed for certain by the 3-4-5 triangle -- which one, and why?', 'This is intentionally tricky. Reward students who identify missing information. If they don''t spot it, push: “Could two different triangles both have sides 3 m, 4 m, 5 m but different angles — or is this triangle''s shape actually fixed? How would you check?”'
